code.Java:
public class Main {
    public static void main(String[] args) {
        final int T = 1;
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;++i){
            sb.append(100).append('\n');
            sb.append(String.format("%.2f", 62.14f)).append('\n');
            sb.append(String.format("%.4E", 9.4607e12)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

